class Solution {
public:
    int nextBeautifulNumber(int n) {
        for (int i = n + 1; ; i++) {
            string str = to_string(i);
            bool valid = true;
            for (int j = 0; j < 10; j++) {
                int count = 0;
                for (int k = 0; k < str.length(); k++) {
                    if (str[k] - '0' == j) count++;
                }
                if (count != j) {
                    valid = false;
                    break;
                }
            }
            if (valid) return i;
        }
    }
};
